module up_counter(reset, clk, q);
input reset, clk;
output [15:0] q;

reg [15:0] count;

  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt) begin
    if (reset) begin
        count <= 0;
    end else begin
        count <= count + 1;
    end
end

assign q = count;

endmodule
